const body = $input.first().json.body || $input.first().json;
const { operation, id, data } = body;

// Get static data as our cache store
const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.plants) workflowStaticData.plants = {};

const CACHE_TTL_DAYS = 30;

function slugify(str) {
  return (str || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
}

function isExpired(entry) {
  if (!entry?.expires_at) return true;
  return new Date(entry.expires_at) < new Date();
}

function ageDays(entry) {
  return Math.floor((Date.now() - new Date(entry.created_at).getTime()) / 86400000);
}

if (operation === 'GET') {
  const key = slugify(id);
  let found = null;

  // Direct key lookup
  if (workflowStaticData.plants[key]) {
    found = workflowStaticData.plants[key];
  } else {
    // Alias search
    for (const [k, entry] of Object.entries(workflowStaticData.plants)) {
      const aliases = (entry.name?.aliases || []).map(a => slugify(a));
      if (aliases.includes(key) || slugify(entry.name?.common) === key) {
        found = entry;
        break;
      }
    }
  }

  if (!found) {
    return [{ json: { found: false, reason: 'not_in_cache', suggestion: 'enrichment_agent' } }];
  }
  if (isExpired(found)) {
    delete workflowStaticData.plants[slugify(found.id)];
    return [{ json: { found: false, reason: 'expired', suggestion: 'enrichment_agent' } }];
  }
  return [{ json: { found: true, data: found, age_days: ageDays(found), source: found.source } }];
}

if (operation === 'SET') {
  const now = new Date();
  const expires = new Date(now);
  expires.setDate(expires.getDate() + CACHE_TTL_DAYS);
  const key = slugify(data.id || data.name?.common || '');
  const entry = { ...data, id: key, created_at: now.toISOString(), updated_at: now.toISOString(), expires_at: expires.toISOString() };
  workflowStaticData.plants[key] = entry;
  return [{ json: { success: true, id: key } }];
}

if (operation === 'DELETE') {
  delete workflowStaticData.plants[slugify(id)];
  return [{ json: { success: true } }];
}

if (operation === 'LIST') {
  const entries = Object.values(workflowStaticData.plants);
  return [{ json: { entries, count: entries.length } }];
}

return [{ json: { error: 'Unknown operation', operation } }];
